SELECT t1.accounts_id, t1.project_id, t1.user_id, t1.name, t1.phone, t1.man_hour, t1.create_time, t1.create_by, t1.update_by, t1.update_time, t1.examine_state, t1.examine_remark, t1.examine_by, t1.examine_time, t1.order_type, t2.project_name FROM sys_accounts t1 left join sys_project t2 on t2.project_id = t1.project_id
and t1.order_type = #{sysAccountsVo.orderTyp e}
and t1.accounts_id = #{sysAccountsVo.accountsId}
and t1.user_id = #{sysAccountsVo.userId}
and t1.project_id = #{sysAccountsVo.projectId}
and t1.phone = #{sysAccountsVo.phone}
and t1.name like concat('%', #{sysAccountsVo.name}, '%')
and t1.create_time BETWEEN #{sysAccountsVo.createTime} and #{sysAccountsVo.endTime}
order by t1.create_time desc

SELECT t1.accounts_id, t1.project_id, t1.user_id, t1.name, t1.phone, t1.man_hour, t1.create_time, t1.create_by, t1.update_by, t1.update_time, t1.examine_state, t1.examine_remark, t1.examine_by, t1.examine_time, t1.order_type, t2.project_name FROM sys_accounts t1 left join sys_project t2 on t2.project_id = t1.project_id
t1.examine_state in("1","2")
and t1.order_type = #{sysAccountsVo.orderType}
and t1.accounts_id = #{sysAccountsVo.accountsId}
and t1.user_id = #{sysAccountsVo.userId}
and t1.project_id = #{sysAccountsVo.projectId}
and t1.phone = #{sysAccountsVo.phone}
and t1.name like concat('%', #{sysAccountsVo.name}, '%')
and t1.create_time BETWEEN #{sysAccountsVo.createTime} and #{sysAccountsVo.endTime}
order by t1.create_time desc
